var CONVERSATIONS_RU_IT = [
{ title: "Заказ кофе в баре", scene: "Вы утром заходите в маленький бар во Флоренции рядом с вокзалом Santa Maria Novella. Нужно быстро заказать кофе и круассан у стойки.", lines: [{ who: "them", it: "Buongiorno, prego.", ru: "Доброе утро, пожалуйста, что желаете?" }, { who: "you", it: "Buongiorno, vorrei un cappuccino.", ru: "Доброе утро, я хотел бы капучино." }, { who: "them", it: "Certo, vuole anche qualcosa da mangiare?", ru: "Конечно, хотите ещё что-нибудь поесть?" }, { who: "you", it: "Sì, un cornetto, per favore.", ru: "Да, круассан, пожалуйста." }, { who: "them", it: "Con crema o semplice?", ru: "С кремом или простой?" }, { who: "you", it: "Semplice, grazie.", ru: "Простой, спасибо." }, { who: "them", it: "Va bene, sono tre euro.", ru: "Хорошо, с вас три евро." }, { who: "you", it: "Posso pagare con carta?", ru: "Можно оплатить картой?" }, { who: "them", it: "Sì, certo.", ru: "Да, конечно." }, { who: "you", it: "Grazie mille.", ru: "Большое спасибо." }, { who: "them", it: "Prego, buona giornata.", ru: "Пожалуйста, хорошего дня." }] },
{ title: "Заселение в отель", scene: "Вы приезжаете в отель в Риме после долгого перелёта. На ресепшене нужно назвать бронирование, показать паспорт и узнать про завтрак.", lines: [{ who: "them", it: "Buonasera, benvenuto in hotel.", ru: "Добрый вечер, добро пожаловать в отель." }, { who: "you", it: "Buonasera, ho una prenotazione.", ru: "Добрый вечер, у меня есть бронирование." }, { who: "them", it: "A nome di chi?", ru: "На чьё имя?" }, { who: "you", it: "A nome di Ivanov.", ru: "На имя Иванов." }, { who: "them", it: "Perfetto, posso avere il passaporto?", ru: "Отлично, можно ваш паспорт?" }, { who: "you", it: "Sì, questo è il mio passaporto.", ru: "Да, вот мой паспорт." }, { who: "them", it: "La sua camera è al terzo piano.", ru: "Ваш номер на третьем этаже." }, { who: "you", it: "La colazione è inclusa?", ru: "Завтрак включён?" }, { who: "them", it: "Sì, dalle sette alle dieci.", ru: "Да, с семи до десяти." }, { who: "you", it: "Dov'è l'ascensore?", ru: "Где лифт?" }, { who: "them", it: "A destra, dopo la reception.", ru: "Направо, после ресепшена." }, { who: "you", it: "Grazie, arrivederci.", ru: "Спасибо, до свидания." }] },
{ title: "Как пройти к вокзалу", scene: "Вы гуляете по Болонье и не можете найти железнодорожный вокзал. Вы останавливаете прохожего и вежливо просите подсказать дорогу.", lines: [{ who: "you", it: "Scusi, mi può aiutare?", ru: "Извините, вы можете мне помочь?" }, { who: "them", it: "Sì, certo.", ru: "Да, конечно." }, { who: "you", it: "Dov'è la stazione?", ru: "Где вокзал?" }, { who: "them", it: "Vada sempre dritto per cinque minuti.", ru: "Идите всё время прямо пять минут." }, { who: "you", it: "Poi devo girare?", ru: "Потом мне нужно повернуть?" }, { who: "them", it: "Sì, giri a sinistra alla piazza.", ru: "Да, поверните налево у площади." }, { who: "you", it: "È lontano?", ru: "Это далеко?" }, { who: "them", it: "No, è abbastanza vicino.", ru: "Нет, довольно близко." }, { who: "you", it: "Può mostrare sulla mappa?", ru: "Можете показать на карте?" }, { who: "them", it: "Certo, è qui.", ru: "Конечно, это здесь." }, { who: "you", it: "Grazie mille.", ru: "Большое спасибо." }, { who: "them", it: "Prego, buon viaggio.", ru: "Пожалуйста, хорошей поездки." }] },
{ title: "Ужин в ресторане", scene: "Вы пришли в тратторию в Тоскане без бронирования. Нужно попросить столик, заказать пасту и узнать рекомендацию официанта.", lines: [{ who: "them", it: "Buonasera, avete una prenotazione?", ru: "Добрый вечер, у вас есть бронирование?" }, { who: "you", it: "No, un tavolo per due, per favore.", ru: "Нет, столик на двоих, пожалуйста." }, { who: "them", it: "Certo, seguitemi.", ru: "Конечно, следуйте за мной." }, { who: "you", it: "Grazie, possiamo avere il menu?", ru: "Спасибо, можно нам меню?" }, { who: "them", it: "Subito. Oggi consiglio la pasta al tartufo.", ru: "Сейчас. Сегодня я рекомендую пасту с трюфелем." }, { who: "you", it: "Sembra molto buona.", ru: "Звучит очень вкусно." }, { who: "them", it: "Volete ordinare?", ru: "Хотите заказать?" }, { who: "you", it: "Sì, vorrei la pasta al tartufo.", ru: "Да, я хотел бы пасту с трюфелем." }, { who: "them", it: "E da bere?", ru: "А пить?" }, { who: "you", it: "Un'acqua naturale e un bicchiere di vino rosso.", ru: "Воду без газа и бокал красного вина." }, { who: "them", it: "Perfetto.", ru: "Отлично." }, { who: "you", it: "Grazie.", ru: "Спасибо." }] },
{ title: "Покупка билета на поезд", scene: "Вы на вокзале Milano Centrale и хотите купить билет до Вероны. Нужно уточнить платформу и время отправления.", lines: [{ who: "them", it: "Buongiorno, dove vuole andare?", ru: "Добрый день, куда вы хотите поехать?" }, { who: "you", it: "Buongiorno, un biglietto per Verona, per favore.", ru: "Добрый день, один билет до Вероны, пожалуйста." }, { who: "them", it: "Solo andata?", ru: "Только туда?" }, { who: "you", it: "Sì, solo andata.", ru: "Да, только туда." }, { who: "them", it: "Il treno parte alle dieci e venti.", ru: "Поезд отправляется в десять двадцать." }, { who: "you", it: "Quanto costa?", ru: "Сколько стоит?" }, { who: "them", it: "Costa quindici euro.", ru: "Стоит пятнадцать евро." }, { who: "you", it: "Posso pagare con carta?", ru: "Можно оплатить картой?" }, { who: "them", it: "Certo.", ru: "Конечно." }, { who: "you", it: "Quale binario?", ru: "Какая платформа?" }, { who: "them", it: "Binario sette.", ru: "Платформа семь." }, { who: "you", it: "Grazie, arrivederci.", ru: "Спасибо, до свидания." }] },
{ title: "Покупка сувенира", scene: "Вы на рынке в Палермо и видите красивую керамическую чашку. Нужно спросить цену, цвет и возможность оплаты картой.", lines: [{ who: "them", it: "Buongiorno, posso aiutarla?", ru: "Добрый день, могу вам помочь?" }, { who: "you", it: "Buongiorno, quanto costa questo?", ru: "Добрый день, сколько это стоит?" }, { who: "them", it: "Costa dodici euro.", ru: "Это стоит двенадцать евро." }, { who: "you", it: "Avete un altro colore?", ru: "У вас есть другой цвет?" }, { who: "them", it: "Sì, abbiamo blu, verde e giallo.", ru: "Да, у нас есть синий, зелёный и жёлтый." }, { who: "you", it: "Mi piace quello blu.", ru: "Мне нравится тот синий." }, { who: "them", it: "È molto bello, fatto a mano.", ru: "Он очень красивый, ручной работы." }, { who: "you", it: "Posso pagare con carta?", ru: "Можно оплатить картой?" }, { who: "them", it: "Sì, alla cassa.", ru: "Да, на кассе." }, { who: "you", it: "Lo prendo.", ru: "Я это беру." }, { who: "them", it: "Perfetto, grazie.", ru: "Отлично, спасибо." }, { who: "you", it: "Grazie a lei.", ru: "Это вам спасибо." }] },
{ title: "В аптеке", scene: "У вас заболела голова во время прогулки по Венеции. Вы заходите в аптеку и объясняете симптом фармацевту.", lines: [{ who: "them", it: "Buongiorno, mi dica.", ru: "Добрый день, говорите." }, { who: "you", it: "Buongiorno, ho mal di testa.", ru: "Добрый день, у меня болит голова." }, { who: "them", it: "Ha anche febbre?", ru: "У вас также температура?" }, { who: "you", it: "No, solo mal di testa.", ru: "Нет, только головная боль." }, { who: "them", it: "Vuole una medicina leggera?", ru: "Хотите лёгкое лекарство?" }, { who: "you", it: "Sì, per favore.", ru: "Да, пожалуйста." }, { who: "them", it: "Prenda questa dopo mangiato.", ru: "Принимайте это после еды." }, { who: "you", it: "Serve una ricetta?", ru: "Нужен рецепт?" }, { who: "them", it: "No, non serve.", ru: "Нет, не нужен." }, { who: "you", it: "Quanto costa?", ru: "Сколько стоит?" }, { who: "them", it: "Sei euro.", ru: "Шесть евро." }, { who: "you", it: "Grazie mille.", ru: "Большое спасибо." }] },
{ title: "Небольшой разговор с местным", scene: "Вы сидите в поезде из Неаполя в Сорренто, и сосед начинает дружелюбный разговор. Вы рассказываете, откуда вы и почему приехали в Италию.", lines: [{ who: "you", it: "Buongiorno, questo posto è libero?", ru: "Добрый день, это место свободно?" }, { who: "them", it: "Sì, certo, prego.", ru: "Да, конечно, пожалуйста." }, { who: "you", it: "Grazie. Vengo dalla Russia.", ru: "Спасибо. Я из России." }, { who: "them", it: "Che bello, è il suo primo viaggio in Italia?", ru: "Как здорово, это ваша первая поездка в Италию?" }, { who: "you", it: "Sì, è il mio primo viaggio qui.", ru: "Да, это моя первая поездка сюда." }, { who: "them", it: "Le piace Napoli?", ru: "Вам нравится Неаполь?" }, { who: "you", it: "Sì, mi piace molto.", ru: "Да, мне очень нравится." }, { who: "them", it: "Dove va adesso?", ru: "Куда вы сейчас едете?" }, { who: "you", it: "Vado a Sorrento per vedere il mare.", ru: "Я еду в Сорренто посмотреть море." }, { who: "them", it: "Il mare lì è bellissimo.", ru: "Море там очень красивое." }, { who: "you", it: "Non vedo l'ora.", ru: "Не могу дождаться." }, { who: "them", it: "Buon viaggio!", ru: "Хорошей поездки!" }] }
];
